using Microsoft.Extensions.Logging;
using SkiaSharp.Views.Maui.Controls.Hosting;

namespace Repro;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .UseSkiaSharp()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
                fonts.AddFont("OpenSans-Semibold.ttf", "OpenSansSemibold");
            });

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

using SkiaSharp;
using SkiaSharp.Views.Maui;

namespace Repro;

public partial class MainPage : ContentPage
{
    private int _frameCount;

    public MainPage()
    {
        InitializeComponent();
    }

    private void OnGLPaintSurface(object sender, SKPaintGLSurfaceEventArgs args)
    {
        _frameCount++;
        var canvas = args.Surface.Canvas;
        var info = args.Info;

        canvas.Clear(SKColors.CornflowerBlue);

        using var paint = new SKPaint
        {
            Color = SKColors.White,
            IsAntialias = true,
            TextSize = 48
        };

        canvas.DrawText($"Frame: {_frameCount}", 50, info.Height / 2f, paint);

        using var circlePaint = new SKPaint
        {
            Color = SKColors.Red,
            IsAntialias = true,
            Style = SKPaintStyle.Fill
        };

        canvas.DrawCircle(info.Width / 2f, info.Height / 4f, 50, circlePaint);

        MainThread.BeginInvokeOnMainThread(() =>
        {
            StatusLabel.Text = $"GL Rendered frame {_frameCount}, GRContext: {(GlView?.GRContext != null ? "OK" : "NULL")}";
        });
    }
}
